function assignCardIdsToModules() {
  const byPrefix = (p: string) => CARDS.filter((c) => c.id.startsWith(p)).map((c) => c.id);
  return {
    diplomaticIds: byPrefix('dc-'),
    unIds: byPrefix('un-'),
    crisisIds: byPrefix('cr-'),
    basicsIds: byPrefix('b-'),
    stateIds: byPrefix('st-'),
    economyIds: byPrefix('ec-'),
    lawIds: byPrefix('lw-'),
    societyIds: byPrefix('so-'),
    academicIds: byPrefix('ac-'),
    phrasesIds: byPrefix('ph-'),
  };
}

export const CARD_IDS_BY_MODULE = assignCardIdsToModules();

export function getCardsByIds(ids: string[]): Card[] {
  const set = new Set(ids);
  return CARDS.filter((c) => set.has(c.id));
}

export function getCardById(id: string): Card | undefined {
  return CARDS.find((c) => c.id === id);
}

/** Поиск по term и translation (без учёта регистра) */
export function searchCards(query: string): Card[] {
  const q = query.trim().toLowerCase();
  if (!q) return [];
  return CARDS.filter(
    (c) =>
      c.term.toLowerCase().includes(q) || c.translation.toLowerCase().includes(q)
  );
}
